package com.eas.ui.admin;
import com.eas.config.Database; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class AdminHomePanel extends JPanel { private final JPanel cards=new JPanel(new GridLayout(2,4,12,12)); public AdminHomePanel(){setLayout(new BorderLayout(12,12));setBorder(BorderFactory.createEmptyBorder(22,22,22,22));add(UITheme.title("Attendance Administration Dashboard"),BorderLayout.NORTH);add(cards,BorderLayout.CENTER);JButton refresh=UITheme.button("REFRESH DASHBOARD");add(refresh,BorderLayout.SOUTH);refresh.addActionListener(e->load());load();}
 private void load(){cards.removeAll();addCard("Active Employees","SELECT COUNT(*) FROM employees WHERE employment_status='ACTIVE'");addCard("Today's Time-Ins","SELECT COUNT(*) FROM attendance_records WHERE attendance_date=CURDATE() AND clock_in IS NOT NULL");addCard("Late Today","SELECT COUNT(*) FROM attendance_records WHERE attendance_date=CURDATE() AND late_minutes>0");addCard("Open Sessions","SELECT COUNT(*) FROM attendance_records WHERE attendance_date=CURDATE() AND clock_in IS NOT NULL AND clock_out IS NULL");addCard("Pending Leave","SELECT COUNT(*) FROM leave_requests WHERE status='PENDING'");addCard("Pending Overtime","SELECT COUNT(*) FROM overtime_requests WHERE status='PENDING'");addCard("Corrections","SELECT COUNT(*) FROM attendance_corrections WHERE status='PENDING'");addCard("Departments","SELECT COUNT(*) FROM departments WHERE status='ACTIVE'");revalidate();repaint();}
 private void addCard(String label,String q){String v="-";try(Connection c=Database.getConnection();Statement s=c.createStatement();ResultSet r=s.executeQuery(q)){if(r.next())v=r.getString(1);}catch(Exception ignored){}JPanel p=new JPanel(new BorderLayout());p.setBorder(BorderFactory.createCompoundBorder(BorderFactory.createLineBorder(UITheme.TEAL),BorderFactory.createEmptyBorder(14,14,14,14)));JLabel n=new JLabel(v);n.setFont(new Font("SansSerif",Font.BOLD,30));n.setForeground(UITheme.NAVY);p.add(n,BorderLayout.CENTER);p.add(new JLabel(label),BorderLayout.SOUTH);cards.add(p);}
}
